        \inputstring={\fenInput} \global\setcounter{line}{0} 
        \let\nextLine = \inputstring\relax
        \advance\counter{line} by 1
        \processFEN \parseFENLine{\nextLine} 
    }

}

% Usage Example
\begin{document}
\drawChessboardFromFEN{rnbqkbnr/pppppppp/8/8/8/8/PPPP1PPP/RNBQKBNR w KQkq - 0 1}{8} % Full FEN
\end{document}
